const axios = require('axios');

const accessToken = $input.item.json.access_token;
const userId = $input.item.json.user_id;

const baseUrl = 'https://api.mercadolibre.com';
const limit = 50;
let offset = 0;
let allItems = [];
let hasMore = true;

async function getItems(offset) {
  try {
    const response = await axios.get(
      `${baseUrl}/users/${userId}/items/search`,
      {
        params: {
          status: 'active',
          limit: limit,
          offset: offset
        },
        headers: {
          'Authorization': `Bearer ${accessToken}`
        }
      }
    );
    return response.data;
  } catch (error) {
    console.error('Error fetching items:', error.message);
    throw error;
  }
}

while (hasMore) {
  const data = await getItems(offset);

  if (data.results && data.results.length > 0) {
    allItems = allItems.concat(data.results);
    offset += limit;

    if (data.results.length < limit || offset >= data.paging.total) {
      hasMore = false;
    }
  } else {
    hasMore = false;
  }

  await new Promise(resolve => setTimeout(resolve, 500));
}

return {
  json: {
    total_items: allItems.length,
    item_ids: allItems,
    access_token: accessToken
  }
};

const item = $input.item.json;
const fullInventory = $node["Get_FULL_Stock"].item.json;

const itemId = item.id || '';
const title = item.title || '';
const price = item.price || 0;
const availableQuantity = item.available_quantity || 0;
const status = item.status || '';
const permalink = item.permalink || '';

let sku = '';
if (item.seller_custom_field) {
  sku = item.seller_custom_field;
}

let stockFull = 0;
let stockFlex = 0;

if (fullInventory && fullInventory.inventories) {
  const fullInv = fullInventory.inventories.find(inv => inv.id && inv.id.includes('FULL'));
  if (fullInv && fullInv.available_quantity) {
    stockFull = fullInv.available_quantity;
  }
}

stockFlex = Math.max(0, availableQuantity - stockFull);
const stockTotal = availableQuantity;

return {
  json: {
    id_ml: itemId,
    sku: sku,
    producto: title,
    stock_bodega: 0,
    stock_full: stockFull,
    stock_flex: stockFlex,
    stock_total: stockTotal,
    precio_venta: price,
    status: status,
    permalink: permalink,
    ultima_actualizacion: new Date().toISOString(),
    shipping_mode: item.shipping?.mode || 'not_specified',
    listing_type: item.listing_type_id || '',
    catalog_listing: item.catalog_listing || false
  }
};

const mlData = $node["Process_Inventory_Data"].item.json;
const sheetData = $node["Load_Current_Sheet_Data"].json;

const existingRow = sheetData.find(row => row.ID_ML === mlData.id_ml);

let finalData = {
  proveedor: existingRow?.Proveedor || '',
  sku: mlData.sku || existingRow?.SKU || '',
  producto: mlData.producto,
  id_ml: mlData.id_ml,
  stock_bodega: existingRow?.Stock_Bodega || 0,
  stock_full: mlData.stock_full,
  stock_flex: mlData.stock_flex,
  stock_total: mlData.stock_total,
  umbral_minimo: existingRow?.Umbral_Minimo || 5,
  costo_unitario: existingRow?.Costo_Unitario || 0,
  precio_venta: mlData.precio_venta,
  status: mlData.status,
  ultima_actualizacion: mlData.ultima_actualizacion,
  permalink: mlData.permalink
};

const stockActual = finalData.stock_total;
const umbral = finalData.umbral_minimo;
finalData.alerta_stock = stockActual < umbral;

return { json: finalData };

const items = $input.item.json.aggregatedItems || [];

if (items.length === 0) {
  return {
    json: {
      send_email: false,
      subject: '',
      body: ''
    }
  };
}

let tableRows = items.map(item => {
  const deficit = item.umbral_minimo - item.stock_total;
  const urgencia = deficit > 10 ? '🔴 URGENTE' : '⚠️ Atención';

  return `
    <tr>
      <td style="padding: 8px; border: 1px solid #ddd;">${urgencia}</td>
      <td style="padding: 8px; border: 1px solid #ddd;">${item.proveedor || 'N/A'}</td>
      <td style="padding: 8px; border: 1px solid #ddd;">${item.sku || 'N/A'}</td>
      <td style="padding: 8px; border: 1px solid #ddd;">${item.producto}</td>
      <td style="padding: 8px; border: 1px solid #ddd; text-align: center;">${item.stock_total}</td>
      <td style="padding: 8px; border: 1px solid #ddd; text-align: center;">${item.umbral_minimo}</td>
      <td style="padding: 8px; border: 1px solid #ddd; text-align: center; font-weight: bold; color: red;">${deficit}</td>
      <td style="padding: 8px; border: 1px solid #ddd;"><a href="${item.permalink}" target="_blank">Ver</a></td>
    </tr>
  `;
}).join('');

const emailBody = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; }
    table { border-collapse: collapse; width: 100%; margin-top: 20px; }
    th { background-color: #f44336; color: white; padding: 12px; text-align: left; }
    tr:nth-child(even) { background-color: #f9f9f9; }
  </style>
</head>
<body>
  <h2>🚨 Alerta de Stock Bajo - ${new Date().toLocaleString('es-CL')}</h2>
  <p>Se detectaron <strong>${items.length} producto(s)</strong> bajo el umbral mínimo de stock:</p>

  <table>
    <thead>
      <tr>
        <th>Urgencia</th>
        <th>Proveedor</th>
        <th>SKU</th>
        <th>Producto</th>
        <th>Stock Actual</th>
        <th>Umbral</th>
        <th>Déficit</th>
        <th>Link</th>
      </tr>
    </thead>
    <tbody>
      ${tableRows}
    </tbody>
  </table>

  <p style="margin-top: 30px; color: #666;">
    Este es un mensaje automático del sistema de gestión de inventario.<br>
    Última actualización: ${new Date().toLocaleString('es-CL')}
  </p>
</body>
</html>
`;

return {
  json: {
    send_email: true,
    subject: `🚨 ALERTA: ${items.length} producto(s) con stock bajo`,
    body: emailBody,
    total_alerts: items.length
  }
};

const now = new Date().toISOString();
const totalItems = $node["Get_All_Items"].json.total_items || 0;
const alerts = $json.total_alerts || 0;

console.log(`✅ Workflow completado exitosamente`);
console.log(`Fecha: ${now}`);
console.log(`Total productos procesados: ${totalItems}`);
console.log(`Alertas generadas: ${alerts}`);

return {
  json: {
    status: 'success',
    timestamp: now,
    total_items: totalItems,
    total_alerts: alerts
  }
};
